export class HealthDashboard extends HTMLElement {
    private _weekActivities: Activity[] = [];
    private _upcomingActivities: Activity[] = [];
    private _allActivities: Activity[] = [];
    private _fabMenuOpen = false;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        const shadow = this.shadowRoot!;
        
        const timeline = shadow.getElementById('health-timeline') as HealthTimeline;
        timeline.addEventListener('click', (e) => {
            const target = e.target as HTMLElement;
            if (target.matches('timeline-day')) {
                const date = (target as any).dayData?.date;
                if (date) {
                    navigate(`/health/day/${date}`);
                }
            } else if (target.matches('.fab-mini') || target.closest('.fab-mini')) {
                const dayEl = target.closest('timeline-day') as TimelineDay;
                if (dayEl) {
                    const date = dayEl.dayData?.date;
                    if (date) {
                        this.openManualAddDialog(date);
                    }
                }
            }
        });

        shadow.getElementById('fab-btn')!.addEventListener('click', () => this.toggleFabMenu());

        shadow.getElementById('fab-food')!.addEventListener('click', () => {
            this.closeFabMenu();
            this.dispatchEvent(createAddFoodEvent({ date: Temporal.Now.plainDateISO().toString(), meal: 'Breakfast' }));
        });
        shadow.getElementById('fab-activity')!.addEventListener('click', () => {
            this.closeFabMenu();
            this.openManualAddDialog(Temporal.Now.plainDateISO().toString());
        });

        const form = shadow.getElementById('activity-form') as HTMLFormElement;
        const dialog = shadow.getElementById('activity-dialog') as HTMLDialogElement;

        dialog.addEventListener('close', () => {
            if (dialog.returnValue === 'save') {
                const title = (shadow.getElementById('act-title') as HTMLInputElement).value;
                const type = (shadow.getElementById('act-type') as HTMLSelectElement).value;
                const date = (shadow.getElementById('act-date') as HTMLInputElement).value;
                const durationStr = (shadow.getElementById('act-duration') as HTMLInputElement).value;
                const duration_minutes = durationStr ? parseInt(durationStr, 10) : undefined;

                if (title && date) {
                    this.dispatchEvent(createSaveActivityEvent({ title, type, date, duration_minutes }));
                }
            }
            form.reset();
        });
    }

    openManualAddDialog(dateStr: string) {
        const shadow = this.shadowRoot!;
        const dialog = shadow.getElementById('activity-dialog') as HTMLDialogElement;
        const dateInput = shadow.getElementById('act-date') as HTMLInputElement;
        dateInput.value = dateStr;
        dialog.showModal();
    }

    private toggleFabMenu(): void {
        this._fabMenuOpen = !this._fabMenuOpen;
        const shadow = this.shadowRoot!;
        shadow.getElementById('fab-menu')!.hidden = !this._fabMenuOpen;
        shadow.getElementById('fab-btn')!.textContent = this._fabMenuOpen ? '×' : '+';
    }

    private closeFabMenu(): void {
        this._fabMenuOpen = false;
        const shadow = this.shadowRoot!;
        shadow.getElementById('fab-menu')!.hidden = true;
        shadow.getElementById('fab-btn')!.textContent = '+';
    }

    showLoading() {
        const shadow = this.shadowRoot!;
        shadow.getElementById('loading')!.hidden = false;
        shadow.getElementById('content')!.hidden = true;
        shadow.getElementById('error')!.hidden = true;
    }

    hideLoading() {
        this.shadowRoot!.getElementById('loading')!.hidden = true;
    }

    showError(message: string) {
        const shadow = this.shadowRoot!;
        const el = shadow.getElementById('error')!;
        el.textContent = message;
        el.hidden = false;
        shadow.getElementById('loading')!.hidden = true;
    }

    showContent() {
        this.shadowRoot!.getElementById('content')!.hidden = false;
    }

    set weekActivities(activities: Activity[]) {
        // weekActivities are passed via allActivities to timeline
    }

    set upcomingActivities(activities: Activity[]) {
        // Future feature: add upcoming to timeline or handle separately
    }

    set allActivities(activities: Activity[]) {
        this._allActivities = activities;
        const timeline = this.shadowRoot!.getElementById('health-timeline') as HealthTimeline;
        if (timeline) {
             timeline.activities = this._allActivities;
        }
        this.updateStats();
    }

    set allNutrition(entries: NutritionEntry[]) {
        const timeline = this.shadowRoot!.getElementById('health-timeline') as HealthTimeline;
        if (timeline) {
             timeline.nutrition = entries;
        }
    }

    set todayNutrition(entries: NutritionEntry[]) {
        // Kept for backward compatibility or future use if needed
    }
    
    set weekNutritionSummary(summaries: DailyNutritionSummary[]) {
        const chart = this.shadowRoot!.getElementById('calorie-trend-chart') as CalorieTrendChart;
        if (chart) chart.weekSummary = summaries;

        const timeline = this.shadowRoot!.getElementById('health-timeline') as HealthTimeline;
        if (timeline && summaries.length > 0) {
             const activeDays = summaries.filter(s => s.total_calories > 0);
             if (activeDays.length > 0) {
                 const total = activeDays.reduce((sum, s) => sum + s.total_calories, 0);
                 timeline.avgCalories = total / activeDays.length;
             } else {
                 timeline.avgCalories = 0;
             }
        }
    }

    private updateStats() {
        const shadow = this.shadowRoot!;
        const timeline = shadow.getElementById('health-timeline') as HealthTimeline;
        if (timeline) {
            timeline.streak = computeStreak(this._allActivities);
        }
    }
}

customElements.define('health-dashboard', HealthDashboard);
